-- Vue finale cron_budget_bonuses (gravité via cron_gravity_factor + agrégat). Une seule instruction.

CREATE OR REPLACE VIEW public.cron_budget_bonuses AS
WITH bwg AS (SELECT * FROM public.cron_budget_bonuses_bwg),
bgf AS (SELECT country_id,effect_type,public.cron_gravity_factor(contrib,gravity_applies,gravity_pct,pop_avg,country_pop) AS final_contrib FROM bwg WHERE effect_type='population' UNION ALL SELECT country_id,effect_type,public.cron_gravity_factor(contrib,gravity_applies,gravity_pct,gdp_avg,country_gdp) FROM bwg WHERE effect_type='gdp' UNION ALL SELECT country_id,effect_type,public.cron_gravity_factor(contrib,gravity_applies,gravity_pct,mil_avg,country_mil) FROM bwg WHERE effect_type='militarism' UNION ALL SELECT country_id,effect_type,public.cron_gravity_factor(contrib,gravity_applies,gravity_pct,ind_avg,country_ind) FROM bwg WHERE effect_type='industry' UNION ALL SELECT country_id,effect_type,public.cron_gravity_factor(contrib,gravity_applies,gravity_pct,sci_avg,country_sci) FROM bwg WHERE effect_type='science' UNION ALL SELECT country_id,effect_type,public.cron_gravity_factor(contrib,gravity_applies,gravity_pct,stab_avg,country_stab) FROM bwg WHERE effect_type='stability'),
bb AS (SELECT country_id,COALESCE(SUM(final_contrib) FILTER (WHERE effect_type='population'),0) AS pop_rate,COALESCE(SUM(final_contrib) FILTER (WHERE effect_type='gdp'),0) AS gdp_rate,COALESCE(SUM(final_contrib) FILTER (WHERE effect_type='militarism'),0) AS mil_delta,COALESCE(SUM(final_contrib) FILTER (WHERE effect_type='industry'),0) AS ind_delta,COALESCE(SUM(final_contrib) FILTER (WHERE effect_type='science'),0) AS sci_delta,COALESCE(SUM(final_contrib) FILTER (WHERE effect_type='stability'),0) AS stab_delta FROM bgf GROUP BY country_id)
SELECT bb.country_id,bb.pop_rate,bb.gdp_rate,bb.mil_delta,bb.ind_delta,bb.sci_delta,bb.stab_delta FROM bb;
